SELECT e.employee_id, e.employee_name, (
  SELECT SUM(sale_amount) 
  FROM sales s 
  WHERE s.employee_id = e.employee_id
) AS total_sales
FROM employees e
WHERE e.employee_id IN (
  SELECT DISTINCT employee_id FROM sales
)
ORDER BY total_sales DESC;

def fibonacci(n):
    # Initialize cache and counters on the first call if needed
    if not hasattr(fibonacci, 'cache'):
        fibonacci.cache = {0: 0, 1: 1}
        fibonacci.call_count = 0
        fibonacci.cache_hits = 0
    fibonacci.call_count += 1
    if n in fibonacci.cache:
        fibonacci.cache_hits += 1
        return fibonacci.cache[n]
    result = fibonacci(n-1) + fibonacci(n-2)
    fibonacci.cache[n] = result
    return result

function getUppercaseUsernames(users) {
  let result = [];
  for (let i = 0; i < users.length; i++) {
    if (users[i] && users[i].name) {
      let name = users[i].name;
      let upperName = "";
      for (let j = 0; j < name.length; j++) {
        upperName += name[j].toUpperCase();
      }
      result.push(upperName);
    }
  }
  return result;
}
